Future<void> uploadToS3() async {
  final s3 = S3(
    accessKey: awsAccessKey,
    secretKey: awsSecretKey,
    region: 'us-east-1',
    sessionToken: '',
  );

  final uploadRequest = PutObjectRequest(
    bucketName: 'your_bucket_name',
    objectName: 'image.jpg',
    data: File('path/to/image.jpg').readAsBytesSync(),
  );

  try {
    final response = await s3.putObject(uploadRequest);
    print(response);
  } on S3Exception catch (e) {
    print('Error uploading file to S3: $e');
  }
}

Future<void> analyzeImageWithGCV() async {
  final gcv = GoogleCloudVisionApi(apiKey: googleCloudVisionApiKey);

  try {
    final response = await gcv.annotateImage({
      'requests': [
        {
          'image': {'source': {'imageUri': 'gs://your_bucket_name/image.jpg'}},
          'features': [{
            'type': 'LABEL_DETECTION',
            'maxResults': 10,
          }]
        },
      ]
    });
    print(response);
  } on GoogleCloudVisionApiException catch (e) {
    print('Error analyzing image with GCV: $e');
  }
}